SELECT p.project_name, p.actual_cost, p.budget
FROM projects p
WHERE p.status = 'canceled' AND p.funding_goal > (
    SELECT AVG(funding_goal)
    FROM projects
);

SELECT AVG(funding_goal) AS avg_funding_goal
FROM projects
WHERE status = 'failed' AND department = 'IT' AND funding_goal > 1000;

SELECT AVG(budget) AS average_failed_project_budget
FROM projects
WHERE status = 'failed' AND department = 'IT';

SELECT pm.name
FROM project_managers pm
WHERE pm.manager_id = (SELECT p.project_manager_id FROM projects p WHERE p.project_name = 'Project A');

SELECT pc.category_name
FROM project_categories pc
WHERE pc.category_id NOT IN (
    SELECT p.category_id 
    FROM projects p
);

SELECT project_id, COUNT(DISTINCT analyst_id) AS unique_analyst_count
FROM analyst_projects
GROUP BY project_id;
